// HasWorkflow applies the HasEdge predicate on the "workflow" edge.
func HasWorkflow() predicate.WorkflowVersion {
	return predicate.WorkflowVersion(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, WorkflowTable, WorkflowColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasWorkflowWith applies the HasEdge predicate on the "workflow" edge with a given conditions (other predicates).
func HasWorkflowWith(preds ...predicate.Workflow) predicate.WorkflowVersion {
	return predicate.WorkflowVersion(func(s *sql.Selector) {
		step := newWorkflowStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// HasAgentRuns applies the HasEdge predicate on the "agent_runs" edge.
func HasAgentRuns() predicate.WorkflowVersion {
	return predicate.WorkflowVersion(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, AgentRunsTable, AgentRunsColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasAgentRunsWith applies the HasEdge predicate on the "agent_runs" edge with a given conditions (other predicates).
func HasAgentRunsWith(preds ...predicate.AgentRun) predicate.WorkflowVersion {
	return predicate.WorkflowVersion(func(s *sql.Selector) {
		step := newAgentRunsStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.WorkflowVersion) predicate.WorkflowVersion {
	return predicate.WorkflowVersion(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.WorkflowVersion) predicate.WorkflowVersion {
	return predicate.WorkflowVersion(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.WorkflowVersion) predicate.WorkflowVersion {
	return predicate.WorkflowVersion(sql.NotPredicates(p))
}
